mapper.select:
SELECT

FROM user u
WHERE u.deleted = 0

    AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))


    AND u.id IN (
        SELECT ur.user_id 
        FROM user_role ur 
        WHERE ur.role_id = #{role} AND ur.status = 1
    )


    AND u.status = #{status}


    AND u.create_time  >=   #{startDate}


    AND u.create_time  <=  #{endDate}

ORDER BY
u.id DESC
LIMIT #{offset}, #{pageSize}

SELECT
u.id, u.username, u.nickname, u.email, u.phone, u.status, u.register_time, u.last_login_time, u.article_count, u.comment_count,
COALESCE(MAX(ur.role_id), 2) as user_role
FROM user u
LEFT JOIN user_role ur ON u.id = ur.user_id AND ur.status = 1
WHERE u.deleted = 0

    AND (u.username LIKE CONCAT('%', #{query.keyword}, '%') OR u.nickname LIKE CONCAT('%', #{query.keyword}, '%') OR u.email LIKE CONCAT('%', #{query.keyword}, '%') OR u.phone LIKE CONCAT('%', #{query.keyword}, '%'))


    AND ur.role_id = #{query.userRole}


    AND u.status = #{query.status}


    AND u.create_time  >=  #{query.startDate}


    AND u.create_time  <=  #{query.endDate}

GROUP BY u.id
ORDER BY u.id DESC
LIMIT #{query.offset}, #{query.pageSize}

