username = #{username}, password = #{password}, nickname = #{nickname}, email = #{email}, email_verified = #{emailVerified}, phone = #{phone}, phone_verified = #{phoneVerified}, avatar = #{avatar}, cover_image = #{coverImage}, signature = #{signature}, gender = #{gender}, birth_date = #{birthDate}, location = #{location}, website = #{website}, follow_count = #{followCount}, follower_count = #{followerCount}, article_count = #{articleCount}, comment_count = #{commentCount}, like_count = #{likeCount}, last_login_time = #{lastLoginTime}, last_login_ip = #{lastLoginIp}, register_ip = #{registerIp}, register_time = #{registerTime}, privacy = #{privacy}, status = #{status}, username_last_modified_time = #{usernameLastModifiedTime}, update_time = #{updateTime}, deleted = #{deleted},
WHERE id = #{id}

UPDATE user
status = #{status}, update_time = now()
WHERE id = #{id}

UPDATE user
last_login_time = #{lastLoginTime}, update_time = now()
WHERE id = #{id}

